/* Helper: index POIs by category for fast filtering. */
const FRENCH_POIS_BY_CAT = FRENCH_POIS.reduce((m, p) => {
  (m[p.cat] = m[p.cat] || []).push(p); return m;
}, {});

/* Helper: index POIs by region. */
const FRENCH_POIS_BY_REGION = FRENCH_POIS.reduce((m, p) => {
  (m[p.region] = m[p.region] || []).push(p); return m;
}, {});

/* Helper: filter POIs by an array of themes (any-of match). */
function frenchPoisWithThemes(themes) {
  const set = new Set(themes);
  return FRENCH_POIS.filter(p => p.themes.some(t => set.has(t)));
}

/* Helper: top-N most notable POIs (score >= threshold). */
function frenchPoisTop(n = 25, scoreFloor = 8) {
  return FRENCH_POIS
    .filter(p => (p.sc || 0) >= scoreFloor)
    .slice()
    .sort((a, b) => (b.sc || 0) - (a.sc || 0))
    .slice(0, n);
}

if (typeof module !== 'undefined') {
  module.exports = { FRENCH_POIS, FRENCH_POIS_BY_CAT, FRENCH_POIS_BY_REGION, frenchPoisWithThemes, frenchPoisTop };
}
